/**
 * Form data sanitization utility for WorkflowTaskDetail component
 * Filters out UI-only properties (SelectLists, dropdown options) before sending to backend
 */

// Properties to exclude from RelatedDataDefModel (nested in UserDefinedFields, RelatedFields, etc.)
const relatedDataDefExcludeProperties = [
  'RelateClasses',
  'relateClasses',
  'DataTypes',
  'dataTypes',
  'Domains',
  'domains',
  'DefaultValueOptions',
  'defaultValueOptions'
];

/**
 * Sanitizes a RelatedDataDefModel object by removing SelectList properties
 * @param {object} relatedDataDef - The RelatedDataDefModel object
 * @returns {object} - Sanitized object
 */
const sanitizeRelatedDataDef = (relatedDataDef) => {
  if (!relatedDataDef || typeof relatedDataDef !== 'object') {
    return relatedDataDef;
  }

  const sanitized = {};
  Object.keys(relatedDataDef).forEach(key => {
    if (!relatedDataDefExcludeProperties.includes(key)) {
      let value = relatedDataDef[key];
      
      // Recursively sanitize nested RelatedDataDefs and RelatedDatas
      if (key === 'RelatedDataDefs' && Array.isArray(value)) {
        value = value.map(item => sanitizeRelatedDataDef(item));
      } else if (key === 'RelatedDatas' && Array.isArray(value)) {
        value = value.map(item => sanitizeRelatedData(item));
      } else if (key === 'Definition' && value && typeof value === 'object') {
        value = sanitizeRelatedDataDef(value);
      }
      
      sanitized[key] = value;
    }
  });
  return sanitized;
};

/**
 * Sanitizes a RelatedData object by removing SelectList properties from nested Definition
 * @param {object} relatedData - The RelatedData object
 * @returns {object} - Sanitized object
 */
const sanitizeRelatedData = (relatedData) => {
  if (!relatedData || typeof relatedData !== 'object') {
    return relatedData;
  }

  const sanitized = { ...relatedData };
  
  // Remove SelectList property
  delete sanitized.ListOfValues;
  delete sanitized.listOfValues;
  
  // Sanitize nested Definition if present
  if (sanitized.Definition && typeof sanitized.Definition === 'object') {
    sanitized.Definition = sanitizeRelatedDataDef(sanitized.Definition);
  }
  
  return sanitized;
};

/**
 * Removes duplicate cased properties from an object (e.g., keeps PascalCase, removes camelCase duplicates)
 * MVC model binder is case-insensitive, so having both FieldName and fieldName causes "duplicate key" error
 * @param {object} obj - The object to deduplicate
 * @returns {object} - Object with only PascalCase versions of properties
 */
const removeDuplicateCasedProperties = (obj) => {
  if (!obj || typeof obj !== 'object') {
    return obj;
  }

  const sanitized = {};
  const seenKeysLower = new Set();

  // Process keys - prefer PascalCase (uppercase first letter) over camelCase
  const keys = Object.keys(obj);
  
  // Sort keys so PascalCase comes first (uppercase letters sort before lowercase in ASCII)
  keys.sort((a, b) => {
    const aFirstUpper = a[0] === a[0].toUpperCase();
    const bFirstUpper = b[0] === b[0].toUpperCase();
    if (aFirstUpper && !bFirstUpper) return -1;
    if (!aFirstUpper && bFirstUpper) return 1;
    return 0;
  });

  keys.forEach(key => {
    const keyLower = key.toLowerCase();
    if (!seenKeysLower.has(keyLower)) {
      seenKeysLower.add(keyLower);
      sanitized[key] = obj[key];
    }
    // Skip if we already have this key (case-insensitive)
  });

  return sanitized;
};

/**
 * Sanitizes a RelatedFieldDef object to match backend expectations
 * Backend expects: FieldName, FieldDescription, FormName, FieldType, RefDomain, IsDataGrid (PascalCase)
 * @param {object} relatedField - The RelatedFieldDef object
 * @returns {object} - Sanitized object with only backend-expected properties in PascalCase
 */
const sanitizeRelatedField = (relatedField) => {
  if (!relatedField || typeof relatedField !== 'object') {
    return relatedField;
  }
  
  // Map to backend-expected properties (PascalCase)
  // Use PascalCase if available, otherwise convert from camelCase
  return {
    FieldName: relatedField.FieldName || relatedField.fieldName || '',
    FieldDescription: relatedField.FieldDescription || relatedField.fieldDescription || '',
    FormName: relatedField.FormName || relatedField.formName || '',
    FieldType: relatedField.FieldType || relatedField.fieldType || '',
    RefDomain: relatedField.RefDomain || relatedField.refDomain || null,
    IsDataGrid: relatedField.IsDataGrid ?? relatedField.isDataGrid ?? false
  };
};

/**
 * Sanitizes form data before sending to backend by removing SelectList and UI-only properties
 * @param {object} formData - The complete form data from React state
 * @returns {object} - Sanitized data safe for backend consumption
 */
export const sanitizeTaskDetailForSave = (formData) => {
  // Properties to exclude (SelectLists and UI-only fields)
  const excludeProperties = [
    // SelectList dropdown options (large arrays - exclude from backend)
    'statuses',
    'Statuses',
    'workQueues', 
    'WorkQueues',
    'actions',
    'Actions', // Large array - exclude from backend
    'thirdPartyApprovalStatuses',
    'ThirdPartyApprovalStatuses', // Large array - exclude from backend
    'recipientSelection',
    'RecipientSelection', // Large array - exclude from backend
    'formLanguageSelection',
    'FormLanguageSelection', // Large array - exclude from backend
    'SecurimateFormSubmissionSelection', // Large array - exclude from backend
    'notificationWorkQueueSelection',
    'NotificationWorkQueueSelection',
    'thirdPartyNotificationSelection',
    'ThirdPartyNotificationSelection',
    'notificationTypeSelection',
    'NotificationTypeSelection',
    'notificationLanguageSelection',
    'NotificationLanguageSelection',
    'categories',
    'Categories',
    'formNames',
    'FormNames',
    
    // UI-only arrays and objects

    'userDefinedFieldsAll',
    'UserDefinedFieldsAll', // Large array - exclude from backend
    'thirdPartyFieldsAll',
    'ThirdPartyFieldsAll', // Large array - exclude from backend
    'relatedFieldsAll',
    'UIAlerts',
    'conditionalSnippetRulesJson',
    
    // UI state properties
    'showCheckBox',
    'highlighted',
    'evaluateAllConditions',
    'isAutoComplete',
    'hasRouteTo',
    'isPrecondition'
  ];

  // Create sanitized object with only the data properties
  const sanitized = {};
  
  Object.keys(formData).forEach(key => {
    if (!excludeProperties.includes(key)) {
      let value = formData[key];
      
      // Clean up SecurimateFormSubmissionSelection to remove items with null/empty Value
      if (key === 'SecurimateFormSubmissionSelection' && Array.isArray(value)) {
        value = value.filter(item => item && item.Value && item.Value.trim() !== '');
      }
      
      // Sanitize nested RelatedDataDefModel arrays (UserDefinedFields)
      if ((key === 'UserDefinedFields' || key === 'userDefinedFields') && Array.isArray(value)) {
        value = value.map(item => sanitizeRelatedDataDef(item));
      }
      
      // Sanitize RelatedFields and ThirdPartyFields - remove duplicate cased properties
      if ((key === 'RelatedFields' || key === 'relatedFields' ||
           key === 'ThirdPartyFields' || key === 'thirdPartyFields') && Array.isArray(value)) {
        value = value.map(item => sanitizeRelatedField(item));
      }
      
      sanitized[key] = value;
    }
  });

  // Handle duplicate ID keys - prefer PascalCase Id over camelCase id
  if (sanitized.Id && sanitized.id) {
    // Both exist - remove the camelCase version to avoid duplicate key error
    delete sanitized.id;
  } else if (sanitized.id && !sanitized.Id) {
    // Only camelCase exists - convert to PascalCase
    sanitized.Id = sanitized.id;
    delete sanitized.id;
  }
  
  // Ensure required properties are present with defaults
  if (sanitized.Id === null || sanitized.Id === undefined || sanitized.Id === '') {
    // Don't set empty string - let the backend handle missing ID
    // This prevents LoadFailure errors
    delete sanitized.Id;
  }
  
  // Ensure ContainerId is present
  if (!sanitized.ContainerId && !sanitized.containerId) {
    console.warn('FORM DATA SANITIZER: ContainerId is missing from form data');
  }

  return sanitized;
};

/**
 * Logs the sanitization process for debugging
 * @param {object} originalData - Original form data
 * @param {object} sanitizedData - Sanitized data
 */
export const logSanitization = (originalData, sanitizedData) => {
  const originalKeys = Object.keys(originalData);
  const sanitizedKeys = Object.keys(sanitizedData);
  const removedKeys = originalKeys.filter(k => !sanitizedKeys.includes(k));
};
